#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000000000

int min(int a, int b) { return a < b ? a : b; }

int digitsum(int n) {
    int sum = 0;
    while (n > 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);
        int min_val = N;
        int min_ops = 0;
        int queue[MAX];
        int front = 0, rear = 0;
        queue[rear++] = N;
        int visited[MAX] = {0};
        visited[N] = 1;
        while (front < rear) {
            int curr = queue[front++];
            if (curr < min_val) {
                min_val = curr;
                min_ops = visited[curr];
            }
            int next1 = curr + D;
            if (next1 <= MAX && !visited[next1]) {
                queue[rear++] = next1;
                visited[next1] = visited[curr] + 1;
            }
            int next2 = digitsum(curr);
            if (next2 <= MAX && !visited[next2]) {
                queue[rear++] = next2;
                visited[next2] = visited[curr] + 1;
            }
        }
        printf("%d %d\n", min_val, min_ops);
    }
    return 0;
}

