        int min_val = N;
        int min_ops = 0;
        queue<int> q;
        unordered_set<int> visited;
        q.push(N);
        visited.insert(N);
        while (!q.empty()) {
            int curr = q.front();
            q.pop();
            if (curr < min_val) {
                min_val = curr;
                min_ops = visited.size();
            }
            int next1 = curr + D;
            if (next1 <= 1000000000 && visited.find(next1) == visited.end()) {
                q.push(next1);
                visited.insert(next1);
            }
            int next2 = digitsum(curr);
            if (next2 <= 1000000000 && visited.find(next2) == visited.end()) {
                q.push(next2);
                visited.insert(next2);
            }
        }
        cout << min_val << " " << min_ops << endl;
    }
