import java.util.Queue;
import java.util.LinkedList;
import java.util.HashSet;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int D = sc.nextInt();
            int min_val = N;
            int min_ops = 0;
            Queue<Integer> q = new LinkedList<>();
            HashSet<Integer> visited = new HashSet<>();
            q.add(N);
            visited.add(N);
            while (!q.isEmpty()) {
                int curr = q.poll();
                if (curr < min_val) {
                    min_val = curr;
                    min_ops = visited.size();
                }
                int next1 = curr + D;
                if (next1 <= 1000000000 && !visited.contains(next1)) {
                    q.add(next1);
                    visited.add(next1);
                }
                int next2 = digitsum(curr);
                if (next2 <= 1000000000 && !visited.contains(next2)) {
                    q.add(next2);
                    visited.add(next2);
                }
            }
            System.out.println(min_val + " " + min_ops);
        }
    }
    public static int digitsum(int n) {
        int sum = 0;
        while (n > 0) {
            sum += n % 10;
            n /= 10;
        }
        return sum;
    }
}

